     1→// web/app/page.tsx
     2→"use client";
     3→
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import { StatsCards } from "@/components/dashboard/stats-cards";
     7→import { RecentReleases } from "@/components/dashboard/recent-releases";
     8→import {
     9→  projects as projectsApi,
    10→  semanticReleases as srApi,
    11→} from "@/lib/api/client";
    12→import { StatusDot } from "@/components/ui/status-dot";
    13→import { VersionChip } from "@/components/ui/version-chip";
    14→import type { SemanticRelease } from "@/lib/api/types";
    15→import { timeAgo } from "@/lib/format";
    16→
    17→interface SRRow extends SemanticRelease {
    18→  _projectName?: string;
    19→}
    20→
    21→function SemanticReleasesColumn() {
    22→  const { data: projectsData } = useSWR("projects-for-sr-dashboard", () =>
    23→    projectsApi.list()
    24→  );
    25→
    26→  const { data: allSRs, isLoading } = useSWR(
    27→    projectsData ? "recent-semantic-releases" : null,
    28→    async () => {
    29→      if (!projectsData?.data?.length) return [];
    30→
    31→      const projectMap = new Map(
    32→        projectsData.data.map((p) => [p.id, p.name])
    33→      );
    34→
    35→      const results = await Promise.all(
    36→        projectsData.data.slice(0, 10).map((p) =>
    37→          srApi.list(p.id, 1).catch(() => null)
    38→        )
    39→      );
    40→
    41→      const srs: SRRow[] = results
    42→        .filter((r): r is NonNullable<typeof r> => r !== null)
    43→        .flatMap((r) => r.data)
    44→        .sort(
    45→          (a, b) =>
    46→            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
    47→        )
    48→        .slice(0, 6)
    49→        .map((sr) => ({
    50→          ...sr,
    51→          _projectName: projectMap.get(sr.project_id),
    52→        }));
    53→
    54→      return srs;
    55→    }
    56→  );
    57→
    58→  return (
    59→    <div
    60→      className="rounded-lg bg-white"
    61→      style={{ border: "1px solid #e8e8e5" }}
    62→    >
    63→      {/* Header */}
    64→      <div
    65→        className="flex items-center justify-between px-5 py-4"
    66→        style={{ borderBottom: "1px solid #e8e8e5" }}
    67→      >
    68→        <h3
    69→          className="font-medium"
    70→          style={{
    71→            fontFamily: "var(--font-dm-sans)",
    72→            fontSize: "13px",
    73→            color: "#111113",
    74→          }}
    75→        >
    76→          Semantic Releases
    77→        </h3>
    78→        <Link
    79→          href="/semantic-releases"
    80→          className="text-sm hover:underline"
    81→          style={{
    82→            fontFamily: "var(--font-dm-sans)",
    83→            fontSize: "13px",
    84→            color: "#e8601a",
    85→          }}
    86→        >
    87→          View all &rarr;
    88→        </Link>
    89→      </div>
    90→
    91→      {/* Body */}
    92→      <div className="p-4 space-y-3">
    93→        {isLoading ? (
    94→          <div
    95→            className="py-8 text-center"
    96→            style={{
    97→              fontFamily: "var(--font-dm-sans)",
    98→              fontSize: "13px",
    99→              color: "#6b7280",
   100→            }}
   101→          >
   102→            Loading...
   103→          </div>
   104→        ) : allSRs && allSRs.length > 0 ? (
   105→          allSRs.map((sr: SRRow) => (
   106→            <Link
   107→              key={sr.id}
   108→              href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
   109→              className="block rounded-lg px-4 py-3 transition-colors hover:bg-[#fafaf9]"
   110→              style={{ border: "1px solid #e8e8e5" }}
   111→            >
   112→              <div className="flex items-center justify-between">
   113→                <span
   114→                  className="font-semibold"
   115→                  style={{
   116→                    fontFamily: "var(--font-fraunces)",
   117→                    fontSize: "15px",
   118→                    color: "#111113",
   119→                  }}
   120→                >
   121→                  {sr._projectName ?? "Unknown Project"}
   122→                </span>
   123→                <VersionChip version={sr.version} />
   124→              </div>
   125→              {sr.report?.summary && (
   126→                <p
   127→                  className="mt-1 line-clamp-1"
   128→                  style={{
   129→                    fontFamily: "var(--font-dm-sans)",
   130→                    fontStyle: "italic",
   131→                    fontSize: "13px",
   132→                    color: "#6b7280",
   133→                  }}
   134→                >
   135→                  {sr.report.summary}
   136→                </p>
   137→              )}
   138→              <div className="mt-2 flex items-center gap-2">
   139→                <StatusDot status={sr.status} />
   140→                <span
   141→                  style={{
   142→                    fontFamily: "var(--font-dm-sans)",
   143→                    fontSize: "12px",
   144→                    color: "#9ca3af",
   145→                  }}
   146→                >
   147→                  {timeAgo(sr.created_at)}
   148→                </span>
   149→              </div>
   150→            </Link>
   151→          ))
   152→        ) : (
   153→          <div className="py-8 text-center">
   154→            <p
   155→              style={{
   156→                fontFamily: "var(--font-fraunces)",
   157→                fontStyle: "italic",
   158→                fontSize: "14px",
   159→                color: "#9ca3af",
   160→              }}
   161→            >
   162→              No semantic releases yet
   163→            </p>
   164→          </div>
   165→        )}
   166→      </div>
   167→    </div>
   168→  );
   169→}
   170→
   171→export default function DashboardPage() {
   172→  return (
   173→    <div className="space-y-6">
   174→      <h1
   175→        style={{
   176→          fontFamily: "var(--font-fraunces)",
   177→          fontSize: "24px",
   178→          fontWeight: 700,
   179→          color: "#111113",
   180→        }}
   181→      >
   182→        Dashboard
   183→      </h1>
   184→      <StatsCards />
   185→      <div className="grid gap-6 lg:grid-cols-2">
   186→        <RecentReleases />
   187→        <SemanticReleasesColumn />
   188→      </div>
   189→    </div>
   190→  );
   191→}
