    17→};
    18→
    19→function segmentLabel(seg: string): string {
    20→  return SEGMENT_LABELS[seg] ?? seg;
    21→}
    22→
    23→export function Header() {
    24→  const pathname = usePathname();
    25→  const segments = pathname.split("/").filter(Boolean);
    26→
    27→  const uuidRe = /^[0-9a-f-]{8,}$/i;
    28→  const breadcrumbs = segments
    29→    .filter((s) => !uuidRe.test(s))
    30→    .map(segmentLabel);
    31→
    32→  const display =
    33→    breadcrumbs.length === 0
    34→      ? "Dashboard"
    35→      : breadcrumbs.join(" / ");
    36→
    37→  return (
    38→    <header
    39→      className="flex h-12 items-center px-6"
    40→      style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
    41→    >
    42→      <p
    43→        className="text-[14px] font-medium text-[#111113]"
    44→        style={{ fontFamily: "var(--font-dm-sans)" }}
    45→      >
    46→        {display}
    47→      </p>
    48→    </header>
    49→  );
    50→}
