    18→/* ------------------------------------------------------------------ */
    19→/*  Helpers                                                            */
    20→/* ------------------------------------------------------------------ */
    21→
    22→function getProviderUrl(
    23→  provider: string,
    24→  repository: string,
    25→  version: string
    26→): string | null {
    27→  switch (provider) {
    28→    case "github":
    29→      return `https://github.com/${repository}/releases/tag/${version}`;
    30→    case "dockerhub":
    31→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    32→    default:
    33→      return null;
    34→  }
    35→}
    36→
    37→function getProviderLabel(provider: string): string {
    38→  switch (provider) {
    39→    case "github":
    40→      return "GitHub";
    41→    case "dockerhub":
    42→      return "Docker Hub";
    43→    default:
    44→      return provider;
    45→  }
    46→}
    47→
    48→/* ------------------------------------------------------------------ */
    49→/*  Component                                                          */
    50→/* ------------------------------------------------------------------ */
    51→
    52→export function ReleaseDetail({ id }: { id: string }) {
    53→  /* Fetch release */
    54→  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
    55→    releasesApi.get(id)
    56→  );
    57→
    58→  const release = releaseData?.data;
    59→
    60→  /* Fetch source info once we have the release */
    61→  const { data: sourceData } = useSWR(
    62→    release ? `source-${release.source_id}` : null,
    63→    () => (release ? sourcesApi.get(release.source_id) : null)
    64→  );
    65→  const source: Source | undefined = sourceData?.data;
    66→
    67→  /* Fetch project info once we have the source */
    68→  const { data: projectData } = useSWR(
    69→    source ? `project-${source.project_id}` : null,
    70→    () => (source ? projectsApi.get(source.project_id) : null)
    71→  );
    72→  const project: Project | undefined = projectData?.data;
    73→
    74→  /* Fetch linked semantic releases (via project) */
    75→  const { data: srData } = useSWR(
    76→    source ? `sr-for-release-${id}` : null,
    77→    async () => {
    78→      if (!source) return [];
    79→      const res = await srApi.list(source.project_id, 1).catch(() => null);
    80→      if (!res?.data) return [];
    81→      /* Filter semantic releases whose version matches this release version */
    82→      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
    83→    }
    84→  );
    85→
    86→  const linkedSRs: SemanticRelease[] = srData ?? [];
    87→
    88→  /* Loading state */
    89→  if (isLoading) {
    90→    return (
    91→      <div
    92→        className="py-16 text-center"
    93→        style={{
    94→          fontFamily: "var(--font-dm-sans)",
    95→          fontSize: "13px",
    96→          color: "#6b7280",
    97→        }}
    98→      >
    99→        Loading...
   100→      </div>

